"use client";

import { type RefObject, useEffect, useRef } from "react";
import { getOwnerView, isNode } from "./utils/element-guards";
import { restoreFocus as restoreFocusTarget } from "./utils/focus-restore";
import { getFocusableElements, getTabbableElements, isFocusable } from "./utils/focusable";
import { useFocusRestore } from "./use-focus-restore";

export interface UseFocusTrapOptions {
  initialFocus?: RefObject<HTMLElement | null>;
  restoreFocus?: boolean;
  enabled?: boolean;
}

interface TrapEntry {
  container: HTMLElement;
  ownerDocument: Document;
  initialFocus: RefObject<HTMLElement | null> | undefined;
  lastFocused: HTMLElement;
  handleKeyDown: (event: KeyboardEvent) => void;
  handleFocusIn: (event: FocusEvent) => void;
  observer: MutationObserver;
  suspended: boolean;
}

interface ActiveTrap {
  container: HTMLElement;
  restoreFocus: boolean;
  release: () => void;
}

// Per-document trap stacks: only the top (last) entry in each document captures focus.
// When a new trap activates, the previous top is suspended (listeners removed).
// When the top trap releases, the next-in-stack is re-armed (listeners re-attached).
const trapStacks = new WeakMap<Document, TrapEntry[]>();

function getTrapStack(ownerDocument: Document): TrapEntry[] {
  let stack = trapStacks.get(ownerDocument);
  if (!stack) {
    stack = [];
    trapStacks.set(ownerDocument, stack);
  }
  return stack;
}

function suspendEntry(entry: TrapEntry): void {
  if (entry.suspended) return;
  entry.ownerDocument.removeEventListener("keydown", entry.handleKeyDown, true);
  entry.ownerDocument.removeEventListener("focusin", entry.handleFocusIn, true);
  entry.observer.disconnect();
  entry.suspended = true;
}

function resumeEntry(entry: TrapEntry): void {
  if (!entry.suspended) return;
  entry.ownerDocument.addEventListener("keydown", entry.handleKeyDown, true);
  entry.ownerDocument.addEventListener("focusin", entry.handleFocusIn, true);
  entry.observer.observe(entry.container, {
    childList: true,
    subtree: true,
    attributes: true,
    attributeFilter: ["disabled", "hidden", "tabindex", "aria-hidden", "inert"],
  });
  entry.suspended = false;
  // Recapture focus into the resumed trap's container
  const target =
    entry.container.contains(entry.lastFocused) &&
    entry.lastFocused.isConnected &&
    isFocusable(entry.lastFocused)
      ? entry.lastFocused
      : pickInitialTarget(entry.container, entry.initialFocus);
  target.focus();
}

function pushTrap(entry: TrapEntry): void {
  const stack = getTrapStack(entry.ownerDocument);
  const prev = stack.at(-1);
  if (prev) suspendEntry(prev);
  stack.push(entry);
}

function removeTrap(entry: TrapEntry): void {
  const stack = getTrapStack(entry.ownerDocument);
  const index = stack.indexOf(entry);
  if (index < 0) return;
  const wasTop = index === stack.length - 1;
  stack.splice(index, 1);
  if (wasTop) {
    const newTop = stack.at(-1);
    if (newTop) resumeEntry(newTop);
  }
}

function pickInitialTarget(
  container: HTMLElement,
  initialFocus: RefObject<HTMLElement | null> | undefined,
): HTMLElement {
  const requested = initialFocus?.current;
  if (requested && container.contains(requested) && isFocusable(requested)) return requested;
  return getFocusableElements(container)[0] ?? container;
}

function isInsideContainer(
  container: HTMLElement,
  target: EventTarget | null,
): target is HTMLElement {
  const View = getOwnerView(container);
  return isNode(target, View) && container.contains(target);
}

// Effect-on-every-render is intentional: React does not re-fire effects when
// containerRef.current mutates while the ref object stays stable.
export function useFocusTrap(
  containerRef: RefObject<HTMLElement | null>,
  options: UseFocusTrapOptions = {},
): void {
  const { initialFocus, restoreFocus = true, enabled = true } = options;
  const activeTrapRef = useRef<ActiveTrap | null>(null);
  const trapEntryRef = useRef<TrapEntry | null>(null);
  // useFocusRestore manages the focus-restore stack so nested overlays
  // restore correctly. Restoration itself happens in this hook's release()
  // so listeners are detached BEFORE focus moves out of the container --
  // otherwise the document-level focusin recapture re-traps the restored
  // target. `restoreOnUnmount: false` prevents the stack hook from moving
  // focus during its own unmount cleanup.
  const { capture } = useFocusRestore({
    enabled: restoreFocus,
    restoreOnUnmount: false,
  });

  // No dependency array on purpose; see hook-level comment above.
  // eslint-disable-next-line react-hooks/exhaustive-deps
  useEffect(() => {
    const nextContainer = enabled ? containerRef.current : null;
    if (
      activeTrapRef.current?.container === nextContainer &&
      activeTrapRef.current.restoreFocus === restoreFocus
    ) {
      return;
    }

    activeTrapRef.current?.release();
    activeTrapRef.current = null;

    if (!nextContainer) return;
    const container = nextContainer;
    const ownerDocument = container.ownerDocument;
    const restoreTarget = capture(ownerDocument);

    const hadTabIndex = container.hasAttribute("tabindex");
    const originalTabIndex = container.getAttribute("tabindex");
    if (!hadTabIndex) container.setAttribute("tabindex", "-1");

    // lastFocused is set after initial focus below
    let lastFocused: HTMLElement = container;

    const recapture = () => {
      const target =
        container.contains(lastFocused) && lastFocused.isConnected && isFocusable(lastFocused)
          ? lastFocused
          : pickInitialTarget(container, initialFocus);
      target.focus();
    };

    const handleFocusIn = (event: FocusEvent) => {
      const target = event.target;
      if (isInsideContainer(container, target)) {
        lastFocused = target;
        // Keep the stack entry in sync so resume() can use it
        if (trapEntryRef.current) trapEntryRef.current.lastFocused = target;
        return;
      }
      recapture();
    };

    const handleKeyDown = (event: KeyboardEvent) => {
      if (event.key !== "Tab") return;

      const focusableEls = getTabbableElements(container);
      if (focusableEls.length === 0) {
        event.preventDefault();
        if (ownerDocument.activeElement !== container) container.focus();
        return;
      }

      const first = focusableEls[0];
      const last = focusableEls[focusableEls.length - 1];
      const activeElement = ownerDocument.activeElement;

      if (!isInsideContainer(container, activeElement)) {
        event.preventDefault();
        (event.shiftKey ? last : first)?.focus();
        return;
      }

      if (!focusableEls.includes(activeElement as HTMLElement)) {
        event.preventDefault();
        (event.shiftKey ? last : first)?.focus();
        return;
      }

      if (event.shiftKey) {
        if (activeElement === first) {
          event.preventDefault();
          last?.focus();
        }
      } else {
        if (activeElement === last) {
          event.preventDefault();
          first?.focus();
        }
      }
    };

    const observer = new MutationObserver(() => {
      if (lastFocused.isConnected && container.contains(lastFocused) && isFocusable(lastFocused))
        return;
      recapture();
    });

    // Build the stack entry and push it BEFORE attaching listeners or
    // focusing. pushTrap suspends the previous top trap so its focusin
    // handler does not recapture focus away from this new trap.
    const entry: TrapEntry = {
      container,
      ownerDocument,
      initialFocus,
      lastFocused,
      handleKeyDown,
      handleFocusIn,
      observer,
      suspended: false,
    };
    trapEntryRef.current = entry;
    pushTrap(entry);

    // Attach listeners and focus now that the outer trap is suspended
    ownerDocument.addEventListener("keydown", handleKeyDown, true);
    ownerDocument.addEventListener("focusin", handleFocusIn, true);
    observer.observe(container, {
      childList: true,
      subtree: true,
      attributes: true,
      attributeFilter: ["disabled", "hidden", "tabindex", "aria-hidden", "inert"],
    });

    const initialTarget = pickInitialTarget(container, initialFocus);
    initialTarget.focus();
    lastFocused = container.contains(ownerDocument.activeElement)
      ? (ownerDocument.activeElement as HTMLElement)
      : initialTarget;
    entry.lastFocused = lastFocused;

    activeTrapRef.current = {
      container,
      restoreFocus,
      release: () => {
        // Detach own listeners BEFORE removing from the stack. removeTrap
        // calls resumeEntry on the outer trap which focuses into the outer
        // container — if our focusin listener is still attached, it would
        // see that focus escaped and recapture, fighting the outer trap.
        ownerDocument.removeEventListener("keydown", handleKeyDown, true);
        ownerDocument.removeEventListener("focusin", handleFocusIn, true);
        observer.disconnect();

        // Remove from stack. This re-arms the outer trap (if any) which
        // recaptures focus into its container.
        removeTrap(entry);
        trapEntryRef.current = null;

        if (!hadTabIndex) {
          container.removeAttribute("tabindex");
        } else if (originalTabIndex !== null) {
          container.setAttribute("tabindex", originalTabIndex);
        }

        // Only restore focus to pre-trap target if there is no outer trap
        // waiting. When an outer trap exists, resumeEntry() already moved
        // focus back into the outer container.
        if (restoreFocus && getTrapStack(ownerDocument).length === 0) {
          restoreFocusTarget(restoreTarget);
        }
      },
    };
  });

  useEffect(() => {
    return () => {
      const activeTrap = activeTrapRef.current;
      if (!activeTrap) return;
      activeTrapRef.current = null;
      activeTrap.release();
    };
  }, []);
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";
import {
  getRestorableFocusTarget,
  type RestoreFocusOptions,
  restoreFocus,
} from "./utils/focus-restore";

export interface UseFocusRestoreOptions extends RestoreFocusOptions {
  enabled?: boolean;
  restoreOnUnmount?: boolean;
  fallback?: HTMLElement | null;
}

export interface UseFocusRestoreReturn {
  capture: (ownerDocument?: Document) => HTMLElement | null;
  restore: () => boolean;
  target: HTMLElement | null;
}

interface FocusRestoreEntry {
  target: HTMLElement | null;
  ownerDocument: Document;
}

const focusRestoreStacks = new WeakMap<Document, FocusRestoreEntry[]>();

function getDefaultDocument(): Document | null {
  return typeof document === "undefined" ? null : document;
}

function getFocusRestoreStack(ownerDocument: Document): FocusRestoreEntry[] {
  let stack = focusRestoreStacks.get(ownerDocument);
  if (!stack) {
    stack = [];
    focusRestoreStacks.set(ownerDocument, stack);
  }
  return stack;
}

function removeEntry(entry: FocusRestoreEntry): void {
  const stack = getFocusRestoreStack(entry.ownerDocument);
  const index = stack.lastIndexOf(entry);
  if (index >= 0) stack.splice(index, 1);
}

function resolveOptions(options: UseFocusRestoreOptions): Required<UseFocusRestoreOptions> {
  return {
    enabled: options.enabled ?? true,
    restoreOnUnmount: options.restoreOnUnmount ?? true,
    preventScroll: options.preventScroll ?? false,
    fallback: options.fallback ?? null,
  };
}

function releaseEntry(
  entry: FocusRestoreEntry,
  shouldRestore: boolean,
  options: Required<UseFocusRestoreOptions>,
): boolean {
  const stack = getFocusRestoreStack(entry.ownerDocument);
  const isTopEntry = stack.at(-1) === entry;
  removeEntry(entry);

  if (!shouldRestore || !options.enabled || !isTopEntry) return false;

  return (
    restoreFocus(entry.target, { preventScroll: options.preventScroll }) ||
    restoreFocus(options.fallback, { preventScroll: options.preventScroll })
  );
}

export function useFocusRestore(options: UseFocusRestoreOptions = {}): UseFocusRestoreReturn {
  const resolvedOptions = resolveOptions(options);
  const optionsRef = useRef(resolvedOptions);
  const entryRef = useRef<FocusRestoreEntry | null>(null);
  const [target, setTarget] = useState<HTMLElement | null>(null);

  // Stable-ref escape hatch: optionsRef is read ONLY inside capture/restore
  // event-driven callbacks and unmount cleanup (never during render), so
  // mid-render writes are safe under concurrent rendering. See AGENTS.md
  // react-useref rules.
  optionsRef.current = resolvedOptions;

  const capture = useCallback((ownerDocument?: Document) => {
    const resolvedOptions = optionsRef.current;
    if (!resolvedOptions.enabled) {
      const entry = entryRef.current;
      if (entry) {
        entryRef.current = null;
        removeEntry(entry);
      }
      setTarget(null);
      return null;
    }

    const doc = ownerDocument ?? resolvedOptions.fallback?.ownerDocument ?? getDefaultDocument();
    if (!doc) {
      const entry = entryRef.current;
      if (entry) {
        entryRef.current = null;
        removeEntry(entry);
      }
      setTarget(null);
      return null;
    }

    const nextTarget = getRestorableFocusTarget(doc) ?? resolvedOptions.fallback;
    const entry = entryRef.current ?? { target: null, ownerDocument: doc };

    removeEntry(entry);
    entry.target = nextTarget;
    entry.ownerDocument = doc;
    entryRef.current = entry;
    getFocusRestoreStack(doc).push(entry);
    setTarget(nextTarget);

    return nextTarget;
  }, []);

  const restore = useCallback(() => {
    const resolvedOptions = optionsRef.current;
    const entry = entryRef.current;

    if (!entry) {
      return resolvedOptions.enabled
        ? restoreFocus(resolvedOptions.fallback, { preventScroll: resolvedOptions.preventScroll })
        : false;
    }

    entryRef.current = null;
    const restored = releaseEntry(entry, true, resolvedOptions);
    setTarget(null);
    return restored;
  }, []);

  useEffect(() => {
    if (resolvedOptions.enabled) return;

    const entry = entryRef.current;
    if (!entry) return;

    entryRef.current = null;
    removeEntry(entry);
    setTarget(null);
  }, [resolvedOptions.enabled]);

  useEffect(() => {
    return () => {
      const entry = entryRef.current;
      if (!entry) return;

      entryRef.current = null;
      releaseEntry(entry, optionsRef.current.restoreOnUnmount, optionsRef.current);
    };
  }, []);

  return { capture, restore, target };
}

import { isHTMLElement } from "./element-guards";

export interface RestoreFocusOptions {
  preventScroll?: boolean;
}

function getDocument(): Document | null {
  return typeof document === "undefined" ? null : document;
}

export function getRestorableFocusTarget(ownerDocument?: Document): HTMLElement | null {
  const doc = ownerDocument ?? getDocument();
  if (!doc) return null;

  const activeElement = doc.activeElement;
  if (!isHTMLElement(activeElement)) return null;
  if (activeElement === doc.body || activeElement === doc.documentElement) return null;
  if (!activeElement.isConnected) return null;

  return activeElement;
}

export function restoreFocus(
  target: HTMLElement | null,
  options: RestoreFocusOptions = {},
): boolean {
  if (!target?.isConnected) return false;

  // Some environments reject the FocusOptions argument (older engines, certain
  // jsdom versions). Fall back to a plain focus() so restoration still works;
  // losing preventScroll is acceptable degradation.
  try {
    target.focus({ preventScroll: options.preventScroll });
  } catch {
    target.focus();
  }

  return target.ownerDocument.activeElement === target;
}

import { isHTMLElement, isHTMLInputElement } from "./element-guards";

const FOCUSABLE_SELECTOR = [
  "a[href]",
  "area[href]",
  "button:not([disabled])",
  'input:not([type="hidden"]):not([disabled])',
  "select:not([disabled])",
  "textarea:not([disabled])",
  "iframe",
  "object",
  "embed",
  "audio[controls]",
  "video[controls]",
  '[contenteditable]:not([contenteditable="false"])',
  "details > summary:first-of-type",
  "[tabindex]:not([disabled])",
].join(",");

function isHidden(element: HTMLElement): boolean {
  let current: HTMLElement | null = element;
  while (current) {
    const style = current.ownerDocument.defaultView?.getComputedStyle(current);
    if (style && (style.display === "none" || style.visibility === "hidden")) {
      return true;
    }
    current = current.parentElement;
  }
  return false;
}

function isInert(element: HTMLElement): boolean {
  return element.closest("[inert]") !== null;
}

function isAriaHidden(element: HTMLElement): boolean {
  // Any aria-hidden="true" ancestor hides the whole subtree. Per ARIA,
  // aria-hidden="false" does not re-expose content hidden by an ancestor.
  return element.closest('[aria-hidden="true"]') !== null;
}

function isInsideDisabledFieldset(element: HTMLElement): boolean {
  let fieldset = element.closest<HTMLFieldSetElement>("fieldset[disabled]");
  while (fieldset) {
    // Element is inside a disabled fieldset; check it isn't inside the first <legend>.
    const legend = fieldset.querySelector(":scope > legend");
    if (legend?.contains(element)) {
      // descendants of the first legend are not disabled per spec; keep searching upward
      fieldset = fieldset.parentElement?.closest<HTMLFieldSetElement>("fieldset[disabled]") ?? null;
      continue;
    }
    return true;
  }
  return false;
}

export function isFocusable(element: HTMLElement | null): boolean {
  if (!isHTMLElement(element)) return false;
  if (!element.matches(FOCUSABLE_SELECTOR)) return false;
  if (isHidden(element)) return false;
  if (isInert(element)) return false;
  if (isAriaHidden(element)) return false;
  if (isInsideDisabledFieldset(element)) return false;
  return true;
}

// jsdom returns compound-selector matches out of tree order; normalize.
const DOCUMENT_POSITION_PRECEDING = 0x02;
const DOCUMENT_POSITION_FOLLOWING = 0x04;

export function documentOrder(a: HTMLElement, b: HTMLElement): number {
  const pos = a.compareDocumentPosition(b);
  if (pos & DOCUMENT_POSITION_FOLLOWING) return -1;
  if (pos & DOCUMENT_POSITION_PRECEDING) return 1;
  return 0;
}

export function getFocusableElements(container: HTMLElement | null): HTMLElement[] {
  if (!container) return [];
  return Array.from(container.querySelectorAll<HTMLElement>(FOCUSABLE_SELECTOR))
    .sort(documentOrder)
    .filter((element) => isFocusable(element));
}

function isRadioInput(element: HTMLElement): element is HTMLInputElement {
  return isHTMLInputElement(element) && element.type === "radio";
}

function getRadioFormIndex(element: HTMLInputElement): number {
  if (!element.form) return -1;
  return Array.from(element.ownerDocument.forms).indexOf(element.form);
}

function getRadioGroupKey(element: HTMLElement): string | null {
  if (!isRadioInput(element) || element.name === "") return null;
  return `${getRadioFormIndex(element)}:${element.name}`;
}

function isRadioGroupTabStop(element: HTMLElement, focusableElements: HTMLElement[]): boolean {
  const groupKey = getRadioGroupKey(element);
  if (groupKey === null) return true;

  const group = focusableElements.filter((candidate) => getRadioGroupKey(candidate) === groupKey);
  const checked = group.find((candidate) => isRadioInput(candidate) && candidate.checked);
  return element === (checked ?? group[0]);
}

function tabIndexOrder(element: HTMLElement): number {
  return element.tabIndex > 0 ? element.tabIndex : Number.MAX_SAFE_INTEGER;
}

export function getTabbableElements(container: HTMLElement | null): HTMLElement[] {
  if (!container) return [];
  const focusableElements = getFocusableElements(container);
  return focusableElements
    .map((element, index) => ({ element, index }))
    .filter(({ element }) => element.tabIndex >= 0)
    .filter(({ element }) => isRadioGroupTabStop(element, focusableElements))
    .sort((a, b) => tabIndexOrder(a.element) - tabIndexOrder(b.element) || a.index - b.index)
    .map(({ element }) => element);
}

export function getFirstFocusableElement(container: HTMLElement | null): HTMLElement | null {
  return getFocusableElements(container)[0] ?? null;
}

export function containsActiveElement(element: HTMLElement): boolean {
  const activeElement = element.ownerDocument.activeElement;
  return isHTMLElement(activeElement) && element.contains(activeElement);
}

export function getOwnerView(value: unknown): (Window & typeof globalThis) | null {
  const element = value as { ownerDocument?: Document } | null;
  return element?.ownerDocument?.defaultView ?? null;
}

export function isHTMLElement(value: unknown): value is HTMLElement {
  const View = getOwnerView(value);
  return Boolean(View && value instanceof View.HTMLElement);
}

export function isHTMLInputElement(value: unknown): value is HTMLInputElement {
  const View = getOwnerView(value);
  return Boolean(View && value instanceof View.HTMLInputElement);
}

export function isHTMLTextAreaElement(value: unknown): value is HTMLTextAreaElement {
  const View = getOwnerView(value);
  return Boolean(View && value instanceof View.HTMLTextAreaElement);
}

export function isHTMLDialogElement(value: unknown): value is HTMLDialogElement {
  const View = getOwnerView(value);
  return Boolean(View && value instanceof View.HTMLDialogElement);
}

export function isNode(
  value: unknown,
  ownerView: (Window & typeof globalThis) | null,
): value is Node {
  return Boolean(ownerView && value instanceof ownerView.Node);
}

export function isInputElement(target: EventTarget | null): boolean {
  if (!isHTMLElement(target)) return false;
  const tag = target.tagName.toLowerCase();
  return tag === "input" || tag === "textarea" || tag === "select" || target.isContentEditable;
}

const NON_EDITABLE_INPUT_TYPES = new Set([
  "button",
  "checkbox",
  "color",
  "file",
  "hidden",
  "image",
  "radio",
  "range",
  "reset",
  "submit",
]);

function hasContentEditableAttribute(element: HTMLElement): boolean {
  if (element.isContentEditable) return true;
  const value = element.getAttribute("contenteditable");
  if (value === null) return false;
  return value === "" || value === "true" || value === "plaintext-only";
}

export function isEditableElement(target: EventTarget | null): boolean {
  if (!isHTMLElement(target)) return false;

  if (isHTMLTextAreaElement(target)) {
    return !target.disabled && !target.readOnly;
  }

  if (isHTMLInputElement(target)) {
    if (target.disabled || target.readOnly) return false;
    const type = (target.type || "text").toLowerCase();
    return !NON_EDITABLE_INPUT_TYPES.has(type);
  }

  return hasContentEditableAttribute(target);
}
